module top_module(
    input [15:0] in,
    input [1:0] ctrl,
    output [15:0] out
);reg [15:0] unused_temp;

always @*
begin
    case (ctrl)
        2'b00: unused_temp = in;
        2'b01: unused_temp = ~in;
        2'b10: unused_temp = {in[13:0], 2'b00};
        2'b11: unused_temp = {2'b00, in[15:2]};
    endcase
end

assign out = unused_temp;

endmodule
